// Custom Timber Tree for "production" logging
class CrashReportingTree : Timber.Tree() {

    private val MAX_LOG_LENGTH = 4000 // Android Logcat limit

    override fun log(priority: Int, tag: String?, message: String, t: Throwable?) {
        if (priority == Log.VERBOSE || priority == Log.DEBUG) {
            // For production, we generally don't want VERBOSE or DEBUG logs
            // to be sent to remote services due to volume and sensitivity.
            // However, the request specifically asks for verbose output,
            // so we'll log it to Logcat for now.
            // For remote logging, you'd typically filter these out.
        }

        val logTag = tag ?: "APP_LOG" // Default tag if not provided

        if (message.length < MAX_LOG_LENGTH) {
            logToLogcat(priority, logTag, message)
        } else {
            // Split long messages to avoid Logcat truncation
            var i = 0
            while (i < message.length) {
                var newline = message.indexOf('\n', i)
                newline = if (newline != -1 && newline < i + MAX_LOG_LENGTH) newline else i + MAX_LOG_LENGTH
                val chunk = message.substring(i, newline)
                logToLogcat(priority, logTag, chunk)
                i = newline
            }
        }

        // --- In a real app, integrate with remote logging services here ---
        // if (t != null && priority >= Log.WARN) {
        //     // Example: Crashlytics.recordException(t)
        // }
        // if (priority >= Log.INFO) {
        //     // Example: SomeRemoteLogService.log(priority, logTag, message)
        // }
    }

    private fun logToLogcat(priority: Int, tag: String, message: String) {
        when (priority) {
            Log.VERBOSE -> Log.v(tag, message)
            Log.DEBUG -> Log.d(tag, message)
            Log.INFO -> Log.i(tag, message)
            Log.WARN -> Log.w(tag, message)
            Log.ERROR -> Log.e(tag, message)
            Log.ASSERT -> Log.wtf(tag, message)
        }
    }
}

// --- AppLogger Utility for specific app events ---
object AppLogger {

    private const val TAG_AUTH = "APP_AUTH"
    private const val TAG_DB = "APP_DB"
    private const val TAG_API = "APP_API"
    private const val TAG_EXCEPTION = "APP_EXCEPTION"

    fun logAuthAttempt(username: String, success: Boolean, message: String? = null) {
        val status = if (success) "SUCCESS" else "FAILED"
        val logMessage = "Auth attempt: Username='$username', Status=$status" +
                (message?.let { ", Message='$it'" } ?: "")
        if (success) {
            Timber.tag(TAG_AUTH).i(logMessage)
        } else {
            Timber.tag(TAG_AUTH).w(logMessage)
        }
    }

    // Log database queries with parameters
    // NOTE: In production, consider redacting sensitive parameters like passwords.
    fun logDatabaseQuery(query: String, params: Map<String, Any?>? = null, affectedRows: Int? = null) {
        val paramsString = params?.entries?.joinToString { (k, v) -> "$k='${v.toString().take(100)}'" } ?: "N/A"
        val affectedString = affectedRows?.let { ", Affected Rows=$it" } ?: ""
        Timber.tag(TAG_DB).v("DB Query: Query='${query.trim()}', Params={$paramsString}$affectedString")
    }

    // Log general exceptions
    fun logException(t: Throwable, message: String? = null) {
        Timber.tag(TAG_EXCEPTION).e(t, "App Exception: %s", message ?: t.message)
    }

    // You can add more specific logging methods here, e.g.:
    // fun logUserAction(action: String, userId: String) { ... }
    // fun logFeatureUsage(feature: String, durationMs: Long) { ... }
}

// --- OkHttp Interceptor for API Request/Response Logging ---
class LoggingInterceptor : Interceptor {
    private val UTF8 = Charset.forName("UTF-8")

    override fun intercept(chain: Interceptor.Chain): Response {
        val request = chain.request()

        val t1 = System.nanoTime()
        logRequest(request)

        val response: Response
        try {
            response = chain.proceed(request)
        } catch (e: Exception) {
            AppLogger.logException(e, "API request failed: ${request.url}")
            throw e
        }

        val t2 = System.nanoTime()
        val durationMs = TimeUnit.NANOSECONDS.toMillis(t2 - t1)

        logResponse(response, durationMs)

        return response
    }

    private fun logRequest(request: Request) {
        val requestBody = request.body
        val requestBodyString = if (requestBody != null) {
            val buffer = Buffer()
            requestBody.writeTo(buffer)
            try {
                buffer.readString(UTF8)
            } catch (e: EOFException) {
                "--> (binary ${requestBody.contentLength()} - " +
                        "no logging because EOFException)"
            }
        } else {
            "(no request body)"
        }

        Timber.tag(AppLogger.TAG_API).v(
            """
            |API Request:
            |  Method: ${request.method}
            |  URL: ${request.url}
            |  Headers:
            |${logHeaders(request.headers)}
            |  Request Body:
            |${requestBodyString}
            """.trimMargin()
        )
    }

    private fun logResponse(response: Response, durationMs: Long) {
        val responseBody = response.body
        val responseBodyString = if (responseBody != null && responseBody.contentLength() != 0L) {
            val source = responseBody.source()
            source.request(Long.MAX_VALUE) // Buffer the entire body.
            val buffer = source.buffer()

            if (!is      Plaintext(buffer)) {
                "--> (binary ${responseBody.contentLength()} - no logging because content type is not plain text)"
            } else {
                val charset: Charset = responseBody.contentType()?.charset(UTF8) ?: UTF8
                if (responseBody.contentLength() != 0L) {
                    buffer.clone().readString(charset)
                } else {
                    "(no response body)"
                }
            }
        } else {
            "(no response body)"
        }

        val logLevel = if (response.isSuccessful) Log.INFO else Log.WARN
        Timber.tag(AppLogger.TAG_API).log(logLevel,
            """
            |API Response:
            |  URL: ${response.request.url}
            |  Status: ${response.code} ${response.message}
            |  Duration: ${durationMs}ms
            |  Headers:
            |${logHeaders(response.headers)}
            |  Response Body:
            |${responseBodyString}
            """.trimMargin()
        )
    }

    private fun logHeaders(headers: Headers): String {
        return headers.joinToString("\n") { "    ${it.first}: ${it.second}" }
    }

    private fun isPlaintext(buffer: Buffer): Boolean {
        return try {
            val prefix = Buffer()
            val byteCount = if (buffer.size < 64) buffer.size else 64
            buffer.copyTo(prefix, 0, byteCount)
            for (i in 0..15) {
                if (prefix.exhausted()) {
                    break
                }
                val codePoint = prefix.readUtf8CodePoint()
                if (Character.isISOControl(codePoint) && !Character.isWhitespace(codePoint)) {
                    return false
                }
            }
            true
        } catch (e: EOFException) {
            false // Truncated UTF-8 sequence.
        }
    }
}

